import {
  some
} from 'min-dash';

/**
 * @typedef { import('../model/Types').Element } Element
 * @typedef { import('../model/Types').ModdleElement } ModdleElement
 */

/**
 * Is an element of the given BPMN type?
 *
 * @param  {Element|ModdleElement} element
 * @param  {string} type
 *
 * @return {boolean}
 */
export function is(element, type) {
  var bo = getBusinessObject(element);

  return bo && (typeof bo.$instanceOf === 'function') && bo.$instanceOf(type);
}


/**
 * Return true if element has any of the given types.
 *
 * @param {Element|ModdleElement} element
 * @param {string[]} types
 *
 * @return {boolean}
 */
export function isAny(element, types) {
  return some(types, function(t) {
    return is(element, t);
  });
}

/**
 * Return the business object for a given element.
 *
 * @param {Element|ModdleElement} element
 *
 * @return {ModdleElement}
 */
export function getBusinessObject(element) {
  const bo = (element && element.businessObject) || element;
  if (bo && typeof bo.get !== 'function') {
    // ensure a `get` method exists to be compatible with code
    // expecting moddle elements (some parsers may return plain objects)
    const proxy = new Proxy(bo, {
      get(target, prop) {
        if (prop === 'get') return function(name) { return target[name]; };
        return target[prop];
      }
    });

    // if we were given an element without a businessObject, attach
    // the proxy so other code accessing `element.businessObject` works
    try {
      if (element && !element.businessObject) {
        element.businessObject = proxy;
      }
    } catch (e) {
      // ignore if element is not extensible
    }

    return proxy;
  }
  return bo;
}

/**
 * Return the di object for a given element.
 *
 * @param {Element} element
 *
 * @return {ModdleElement}
 */
export function getDi(element) {
  return element && element.di;
}